  f2: { id: "f2", name: "beta.png", size: 2048, contentType: "image/png", etag: 'W/"2048-5899b37f0211f372"' },
  f3: { id: "f3", name: "gamma.json", size: 512, contentType: "application/json", etag: 'W/"512-3a0307a756bd191e"' },
